import React from 'react'
import {App} from './App'
// import swal from 'sweetalert';
// import { useNavigate } from "react-router-dom";
import { Link } from "react-router-dom";
import { useHistory } from "react-router-dom";


const initialFormData = Object.freeze({
    firstname: "",
    lastname: "",
    email: "",
    password: "",
    contact: "",
    dob: ""
});

async function loginUser(credentials) {
  return fetch('http://localhost:9000/users', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(credentials)
  })
    .then((data) =>{ 
      console.log(data)
      return data.json()
    })
 }

const SignUp = () => {
  // const navigate = useNavigate();
  const history = useHistory();
  const [formData, updateFormData] = React.useState(initialFormData);

  const handleChange = (e) => {
    updateFormData({
      ...formData,
      [e.target.name]: e.target.value.trim()
    });
  };

  const handleSubmit = async (e) => {

    e.preventDefault()
    console.log(formData);
    // ... submit to API or something
    const response = await loginUser(
      formData,
    );
    if (response.token) {
      console.log(response)
      console.log("Login Success")
      // <Route path="./App.js" component={App} /> 
      // navigate('/app.js');
      history.push("/index.html");
    } else {
      console.log(response)
      console.log("Login Failed")
      // swal("Failed", response.message, "error");
    }
  };
  return (
    <>
      <div className="card text-center" style={{ marginTop: '10%', marginLeft: '35%', marginRight: '35%' }}>
        <div className="card-body">
          <h5 className="card-title">Sign up</h5>

          <div className="form-outline mb-4">
            <input name = "firstname" type="text" id="form2Example1" className="form-control"  onChange={handleChange} />
            <label className="form-label" htmlFor="form2Example1">First Name</label>
          </div>
          <div className="form-outline mb-4">
            <input name = "lastname" type="text" id="form2Example1" className="form-control"  onChange={handleChange} />
            <label className="form-label" htmlFor="form2Example1">Last Name</label>
          </div>
          <div className="form-outline mb-4">
            <input name = "email" type="email" id="form2Example1" className="form-control"  onChange={handleChange} />
            <label className="form-label" htmlFor="form2Example1">Email address</label>
          </div>

          {/* Password input */}
          <div className="form-outline mb-4">
            <input name = "password" type="password" id="form2Example2" className="form-control"  onChange={handleChange}/>
            <label className="form-label" htmlFor="form2Example2">Password</label>
          </div>
          <div className="form-outline mb-4">
            <input name = "contact" type="text" id="form2Example1" className="form-control"  onChange={handleChange} />
            <label className="form-label" htmlFor="form2Example1">Contact</label>
          </div>
          <div className="form-outline mb-4">
            <input name = "dob" type="text" id="form2Example1" className="form-control"  onChange={handleChange} />
            <label className="form-label" htmlFor="form2Example1">Date of birth</label>
          </div>
          <button type="button" className="btn btn-primary btn-block mb-4" onClick={handleSubmit}>Submit</button>
        </div>
      </div>
    </>
  )
}

export default Login;
